output_format.json_schema:
{
  "contract_metadata": {
    "contract_type": "employment",
    "parties": ["Company Name", "Employee/Contractor Name"],
    "effective_date": "YYYY-MM-DD" (or null if not found),
    "term_length": "At-will | X years | Through YYYY-MM-DD | Perpetual | 'Not specified'",
    "total_value": "$XXX,XXX annual salary | $XXX,XXX total contract value | $XX/hour estimated | 'Variable' | 'Not specified'",
    "has_exhibits": true|false,
    "is_signed": true|false,
    "document_pages": 0,

    // Employment-specific fields
    "employment_type": "employee|independent_contractor|consultant",
    "role_title": "Job title",
    "jurisdiction": "State/Country where employment governed",
    "classification": "exempt|non_exempt|contractor",
    "level": "executive|senior|mid|junior"
  },

  // IMPORTANT: Guidance for employment-specific base fields:
  // - term_length: Extract employment duration. Examples:
  //   * "At-will" for at-will employment
  //   * "2 years" for fixed-term contracts
  //   * "Through 2026-12-31" if specific end date
  //   * "Perpetual" for ongoing arrangements without end date
  // - total_value: Calculate total compensation value. Examples:
  //   * "$120,000 annual salary" for salaried employees
  //   * "$250,000 total contract value" for 2-year contractor at $125k/year
  //   * "$150/hour estimated $300,000 annually" for hourly contractors
  //   * "Variable - commission-based" if compensation is variable
  // - has_exhibits: Check for attachments like benefit plans, equity agreements,
  //   commission structures, non-compete schedules, etc.

  "key_terms": {
    "compensation": {
      "base_compensation": "$XXX,XXX annual salary or $XX/hour or $XXX,XXX contract value",
      "payment_frequency": "Monthly|Bi-weekly|Hourly|Upon milestones",
      "bonus_structure": "Description of bonus or commission plan",
      "equity_compensation": "Description of stock options, RSUs, or equity grants",
      "benefits": "Health insurance, 401k, vacation days, other benefits",
      "clarity_score": "clear|some_ambiguity|unclear",
      "concerns": ["List specific concerns with compensation provisions"],
      "extracted_text": "Section X.Y: Verbatim quote of key compensation clause"
    },

    "ip_assignment": {
      "assignment_scope": "All work-related inventions|Limited scope|No assignment",
      "covers_inventions_discoveries": true|false,
      "prior_ip_carveout": true|false,
      "state_law_compliant": "Compliant with [state] law|May violate [state] law|Unknown",
      "disclosure_obligation": true|false,
      "moral_rights_covered": true|false,
      "concerns": ["List specific concerns with IP assignment"],
      "extracted_text": "Section X.Y: Verbatim quote of key IP clause"
    },

    "confidentiality": {
      "confidentiality_defined": true|false,
      "term": "Indefinite for trade secrets|X years post-termination|During employment only",
      "appropriate_exceptions": true|false,
      "return_of_materials": true|false,
      "concerns": ["List specific concerns with confidentiality provisions"],
      "extracted_text": "Section X.Y: Verbatim quote of key confidentiality clause"
    },

    "restrictive_covenants": {
      "non_compete": {
        "present": true|false,
        "duration": "X months/years or 'N/A'",
        "geographic_scope": "Description or 'N/A'",
        "enforceability_assessment": "Likely enforceable|Questionable|Likely unenforceable|N/A",
        "concerns": ["List enforceability concerns"]
      },
      "non_solicitation": {
        "present": true|false,
        "covers_customers": true|false,
        "covers_employees": true|false,
        "duration": "X months/years or 'N/A'",
        "reasonableness": "Reasonable|Potentially excessive|N/A",
        "concerns": ["List concerns"]
      },
      "consideration_provided": "Yes|No|Not required",
      "extracted_text": "Section X.Y: Verbatim quote of key restrictive covenant clause"
    },

    "termination": {
      "at_will_status": "At-will clearly stated|At-will but contradicted|Fixed term|Unclear",
      "for_cause_definition": "Description of cause termination grounds",
      "notice_period": "X weeks or 'None required'",
      "severance": {
        "provided": true|false,
        "trigger": "Without-cause termination|Any termination|Change of control",
        "amount": "Description of severance package",
        "concerns": ["List concerns about severance"]
      },
      "equity_treatment": "Description of what happens to unvested equity",
      "concerns": ["List specific concerns with termination provisions"],
      "extracted_text": "Section X.Y: Verbatim quote of key termination clause"
    },

    "classification_analysis": {
      "stated_classification": "Employee|Independent contractor",
      "control_factors": "Description of control indicators",
      "benefits_factors": "Description of benefits and tax treatment",
      "misclassification_risk": "Low|Medium|High",
      "concerns": ["List misclassification concerns"],
      "extracted_text": "Section X.Y: Verbatim quote relevant to classification"
    },

    "other_terms": {
      "work_location": "Office location|Remote|Hybrid",
      "start_date": "YYYY-MM-DD or 'To be determined'",
      "contingencies": "Background check, reference checks, other conditions",
      "dispute_resolution": "Litigation|Arbitration|Mediation",
      "reporting_structure": "Reports to [title/name]",
      "policy_compliance": "Must comply with company policies|Not mentioned"
    }
  },

  "risk_assessment": {
    "overall_risk_level": "high|medium|low",
    "risk_score": 0-100,
    "risk_score_breakdown": {
      "ip_protection_risk": 0-100,
      "legal_compliance_risk": 0-100,
      "compensation_clarity": 0-100,
      "restrictive_covenant_enforceability": 0-100,
      "misclassification_risk": 0-100
    },

    "red_flags": [
      {
        "id": "RF-001",
        "category": "IP_Assignment|Confidentiality|Non_Compete|Compensation|Termination|Classification|Other",
        "severity": "critical|high",
        "issue": "Brief description of the critical issue",
        "detail": "Detailed explanation of why this is a red flag",
        "clause_reference": "Section X.Y, Page Z",
        "recommendation": "Specific action to take (revise, add, clarify, seek legal review)",
        "business_impact": "Explanation of potential consequences"
      }
    ],

    "yellow_flags": [
      {
        "id": "YF-001",
        "category": "IP_Assignment|Confidentiality|Non_Compete|Compensation|Termination|Classification|Other",
        "issue": "Brief description of the concern",
        "detail": "Explanation of why this warrants attention",
        "clause_reference": "Section X.Y, Page Z",
        "recommendation": "Suggested action or revision"
      }
    ],

    "positive_findings": [
      {
        "category": "IP_Assignment|Confidentiality|Non_Compete|Compensation|Termination|Classification|Other",
        "finding": "Description of favorable term",
        "why_positive": "Explanation of benefit or good practice",
        "clause_reference": "Section X.Y"
      }
    ]
  },

  "human_review_required": {
    "required": true|false,
    "reasons": ["List reasons why human review is needed"],
    "specific_questions": ["Specific questions for HR/legal reviewer to answer"],
    "priority": "urgent|high|normal",
    "jurisdiction_specific_issues": ["List any jurisdiction-specific legal concerns"],
    "ambiguous_clauses": [
      {
        "clause": "Description of ambiguous provision",
        "why_ambiguous": "Explanation of the ambiguity",
        "possible_interpretations": ["Interpretation A", "Interpretation B"],
        "recommendation": "What should be clarified"
      }
    ]
  },

  "executive_summary": {
    "contract_overview": "One sentence describing the employment role, level, and key compensation",
    "key_findings": [
      "First critical finding (use prefix: HIGH RISK/MEDIUM RISK/LOW RISK/POSITIVE as appropriate)",
      "Second critical finding with specific employment law or company risk",
      "Third critical finding if applicable (limit to 3-4 most important items)"
    ],
    "recommendation": "Clear action: APPROVE / NEGOTIATE [specific items] / REJECT / SEEK LEGAL/HR REVIEW"
  },

  "recommendations": [
    {
      "priority": "high|medium|low",
      "action": "approve|revise|reject|clarify|seek_legal_review",
      "description": "Specific recommendation",
      "rationale": "Why this action is important"
    }
  ],

  "next_steps": "Specific immediate actions for HR/legal team",

  "confidence_score": 0-100,
  "confidence_explanation": "Brief explanation of why confidence is at this level (note jurisdiction-specific issues if applicable)"
}

example.analysis_output:
{
  "ip_assignment": {
    "assignment_scope": "No assignment provision present",
    "covers_inventions_discoveries": false,
    "prior_ip_carveout": false,
    "disclosure_obligation": false,
    "concerns": [
      "No IP assignment clause - Company may not own software employee creates",
      "For engineering role, IP assignment is critical",
      "Without assignment, employee could claim ownership of their work",
      "Could create disputes over ownership of products/features"
    ]
  },
  "risk_assessment": {
    "overall_risk_level": "high",
    "risk_score": 90,
    "red_flags": [
      {
        "category": "IP_Assignment",
        "severity": "critical",
        "issue": "No IP assignment provision for software engineering role",
        "detail": "This employment agreement lacks any IP assignment clause. For a Senior Software Engineer who will be creating software products, this is a critical omission. Without IP assignment, the company may not own the work product created by this employee. Under default copyright law, the employee could claim ownership of code, inventions, and other IP they create. This could lead to ownership disputes and prevent company from using or commercializing employee's work.",
        "recommendation": "MUST ADD: Comprehensive IP assignment clause assigning all work-related inventions, discoveries, and creations to Company. Include disclosure obligation and carve-out for prior IP. Ensure compliance with applicable state law (e.g., California Labor Code 2870 if in CA).",
        "business_impact": "Company may not own critical software and inventions created by engineer - existential business risk"
      }
    ]
  }
}

{
  "restrictive_covenants": {
    "non_compete": {
      "present": true,
      "duration": "2 years post-termination",
      "geographic_scope": "United States (nationwide)",
      "enforceability_assessment": "Unenforceable - California prohibits employee non-competes",
      "concerns": [
        "Contract governed by California law",
        "California Business & Professions Code Section 16600 voids non-compete agreements",
        "This non-compete is unenforceable and should be removed",
        "Including unenforceable provision could create legal liability"
      ]
    }
  },
  "risk_assessment": {
    "overall_risk_level": "high",
    "risk_score": 85,
    "red_flags": [
      {
        "category": "Non_Compete",
        "severity": "critical",
        "issue": "Non-compete agreement in California (unenforceable)",
        "detail": "This agreement includes a 2-year non-compete provision and is governed by California law. Under California Business & Professions Code Section 16600, non-compete agreements are void and unenforceable except in very limited circumstances (sale of business, dissolution of partnership). Including this unenforceable provision could expose company to legal claims for unlawful restraint of trade. Employee could also argue the entire restrictive covenant section is void.",
        "recommendation": "REMOVE non-compete provision entirely. REPLACE with: (1) Strong non-solicitation of customers and employees (enforceable in CA), (2) Robust confidentiality and trade secret protection, (3) IP assignment provisions.",
        "business_impact": "Unenforceable provision creates legal risk; company may face claims for attempting to restrict employment"
      }
    ]
  }
}

{
  "classification_analysis": {
    "stated_classification": "Independent contractor",
    "control_factors": "Company controls hours (9-5), location (company office), equipment (company-provided), supervision (reports to VP)",
    "benefits_factors": "Company provides health insurance and paid vacation (employee benefits)",
    "misclassification_risk": "High",
    "concerns": [
      "Contractor treated as employee (set hours, location, supervision)",
      "Company provides employee-like benefits (health insurance, vacation)",
      "Exclusive full-time arrangement suggests employment relationship",
      "Company controls how, when, and where work is performed",
      "Fails IRS common law test and economic realities test for contractor status"
    ]
  },
  "risk_assessment": {
    "overall_risk_level": "high",
    "risk_score": 95,
    "red_flags": [
      {
        "category": "Classification",
        "severity": "critical",
        "issue": "High risk of contractor misclassification",
        "detail": "This agreement labels the person as an independent contractor but treats them as an employee. Red flags: (1) Company controls work hours and location, (2) Company provides equipment, (3) Contractor reports to manager, (4) Company provides employee benefits (health insurance, vacation), (5) Full-time exclusive relationship. Under IRS rules and DOL guidance, this person is economically dependent on company and should be classified as an employee. Misclassification creates significant legal and tax liability.",
        "recommendation": "MUST REVIEW with employment counsel. Either: (1) Reclassify as W-2 employee with appropriate terms, OR (2) Restructure to true independent contractor relationship (contractor controls when/how/where work performed, no benefits, can work for others, project-based not ongoing).",
        "business_impact": "Back taxes, penalties, benefits claims, wage/hour violations, potential DOL/IRS audit - could be hundreds of thousands in liability"
      }
    ]
  }
}

{
  "ip_assignment": {
    "assignment_scope": "All work-related inventions, discoveries, and works of authorship",
    "covers_inventions_discoveries": true,
    "prior_ip_carveout": true,
    "state_law_compliant": "Compliant with California Labor Code 2870",
    "disclosure_obligation": true,
    "moral_rights_covered": true,
    "concerns": []
  },
  "risk_assessment": {
    "overall_risk_level": "low",
    "positive_findings": [
      {
        "category": "IP_Assignment",
        "finding": "Comprehensive, compliant IP assignment provision",
        "why_positive": "This IP assignment clause includes all critical elements: (1) Covers inventions, discoveries, and works of authorship, (2) Clear scope tied to Company business and use of Company resources, (3) Disclosure obligation, (4) Assignment of ownership and agreement to execute documents, (5) Compliant with California Labor Code 2870 with appropriate carve-out for employee's own-time, own-resources inventions unrelated to Company business. This protects Company's IP while respecting employee rights under state law.",
        "clause_reference": "Section 6"
      }
    ]
  }
}

{
  "executive_summary": {
    "contract_overview": "Senior Engineering Manager employment agreement with $180K salary, $36K target bonus, 100K options over 4 years",
    "key_findings": [
      "HIGH RISK: 12-month non-compete covering entire software industry likely unenforceable and exposes company to legal challenges",
      "MEDIUM RISK: Unlimited IP assignment including off-hours inventions may violate state law protections for employee IP rights",
      "POSITIVE: Competitive compensation package with standard vesting schedule aligns with market rates"
    ],
    "recommendation": "REVISE before offering - narrow non-compete to specific competitors/geography, add IP assignment carve-outs per state law"
  },
  "risk_assessment": {
    "overall_risk_level": "high",
    "risk_score": 70
  }
}
